import torch, math
def swiglu_fan_in(num_experts, hidden_size, intermediate_dim):
    # gate_proj/up_proj: std = 1/sqrt(hidden_size), NOT kaiming fan_in
    # kaiming on (E, fan_in, fan_out) would use dim0=fan_out wrongly
    gate_std = 1.0 / math.sqrt(hidden_size)
    down_std = 1.0 / math.sqrt(intermediate_dim)
    return gate_std, down_std
